`timescale 1ps/1ps `define OK 12 `define INCORRECT 13 module stimulus_gen(input clk, output logic in); initial begin repeat(100) @(posedge clk, negedge clk) begin in <= $random; end #1 $finish; end endmodule module tb(); typedef struct packed { int errors; int errortime; int errors_out; int errortime_out; int clocks; } stats; stats stats1; wire[511:0] wavedrom_title; wire wavedrom_enable; int wavedrom_hide_after_time; reg clk = 0; initial forever #5 clk = ~clk; logic in; logic out_ref; logic out_dut; initial begin $dumpfile("wave.vcd"); $dumpvars(1, stim1.clk, tb_mismatch, clk, in, out_ref, out_dut); end wire tb_match; wire tb_mismatch = ~tb_match; stimulus_gen stim1(clk, .*, in); RefModule good1(clk, in, out(out_ref)); TopModule top_module1(clk, in, out(out_dut)); bit strobe = 0; task wait_for_end_of_timestep; repeat(5) begin strobe <= !strobe; @(strobe); end endtask final begin if (stats1.errors_out) $display("SIMULATION FAILED - %d MISMATCHES DETECTED, FIRST AT TIME %d", stats1.errors_out, stats1.errortime_out); else $display("SIMULATION PASSED"); $display("Total mismatched samples is %d out of %d samples", stats1.errors, stats1.clocks); $display("Simulation finished at %d ps", $time); $display("Mismatches: %d in %d samples", stats1.errors, stats1.clocks); end assign tb_match = ( {out_ref} === ({out_ref} ^ {out_dut} ^ {out_ref}) ); always @(posedge clk, negedge clk) begin stats1.clocks++; if (!tb_match) begin if (stats1.errors == 0) stats1.errortime = $time; stats1.errors++; end if (out_ref !== ({out_ref} ^ {out_dut} ^ {out_ref})) begin if (stats1.errors_out == 0) stats1.errortime_out = $time; stats1.errors_out = stats1.errors_out + 1'b1; end end initial begin #1000000 $display("TIMEOUT"); $finish(); end endmodule